// Script de registro de estímulos en pulsaciones a un clavier
// Este script registra estímulos en pulsaciones de teclado en tiempo real

// Variables globales
let estímulos = [];
let tiempoInicio = null;
let tiempoAnterior = null;

// Función para registrar un estímulo
function registrarEstímulo(tecla, tiempo) {
    const estímulo = {
        tecla: tecla,
        tiempo: tiempo,
        intervalo: tiempo - (tiempoAnterior || tiempo)
    };
    estímulos.push(estímulo);
    tiempoAnterior = tiempo;
}

// Función para iniciar el registro
function iniciarRegistro() {
    tiempoInicio = Date.now();
    tiempoAnterior = null;
    estímulos = [];
    console.log("Registro iniciado.");
}

// Función para detener el registro
function detenerRegistro() {
    console.log("Registro detenido.");
    console.log("Estímulos registrados:", estímulos);
}

// Evento de teclado
document.addEventListener('keydown', function(event) {
    const tiempoActual = Date.now() - tiempoInicio;
    registrarEstímulo(event.key, tiempoActual);
});

